// Extraer el JSON de la respuesta de Ollama
const ollamaResponse = $input.first().json.response;
let estrategia;

try {
  // Ollama devuelve el texto en 'response'. Intentar parsear JSON.
  const cleaned = ollamaResponse
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();
  estrategia = JSON.parse(cleaned);
} catch (e) {
  // Fallback: intentar extraer JSON con regex
  const match = ollamaResponse.match(/\{[\s\S]*\}/);
  if (match) {
    estrategia = JSON.parse(match[0]);
  } else {
    throw new Error(`No se pudo parsear respuesta del Estratega: ${ollamaResponse.substring(0, 200)}`);
  }
}

// Propagar datos del item original + estrategia
const prevData = $('🔒 Sheets — Lock PROCESSING').first().json;

return [{
  json: {
    ...prevData,
    moraleja: estrategia.moraleja || '',
    conflicto: estrategia.conflicto || '',
    escenario: estrategia.escenario || '',
    tono_sugerido: estrategia.tono_sugerido || 'reflexivo',
    estrategia_raw: JSON.stringify(estrategia)
  }
}];

