// Extraer el JSON array de los 12 pasos
const ollamaResponse = $input.first().json.response;
let blueprint;

try {
  const cleaned = ollamaResponse
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .replace(/<think>[\s\S]*?<\/think>/g, '')
    .trim();
  blueprint = JSON.parse(cleaned);
} catch (e) {
  const match = ollamaResponse.match(/\[[\s\S]*\]/);
  if (match) {
    blueprint = JSON.parse(match[0]);
  } else {
    throw new Error(`No se pudo parsear blueprint del Arquitecto: ${ollamaResponse.substring(0, 300)}`);
  }
}

if (!Array.isArray(blueprint) || blueprint.length < 10) {
  throw new Error(`Blueprint inválido: se esperaban 12 pasos, se obtuvieron ${Array.isArray(blueprint) ? blueprint.length : 0}`);
}

// Propagar datos
const prevData = $('⚙️ Parsear Estrategia').first().json;

return [{
  json: {
    ...prevData,
    blueprint: blueprint,
    blueprint_json: JSON.stringify(blueprint)
  }
}];

// COMPILAR EL MEGA-PROMPT PARA EL ESCRITOR (Qwen 3.5 27B)
const data = $input.first().json;
const blueprint = data.blueprint;

// Construir la narrativa paso a paso
let pasosTexto = '';
for (const paso of blueprint) {
  pasosTexto += `\n### PASO ${paso.paso}: ${paso.nombre_campbell}\n`;
  pasosTexto += `**Capítulo:** ${paso.titulo_capitulo}\n`;
  pasosTexto += `**Resumen:** ${paso.resumen}\n`;
  pasosTexto += `**Personajes:** ${paso.personajes.join(', ')}\n`;
  pasosTexto += `**Emoción dominante:** ${paso.emocion}\n`;
}

const megaPrompt = `Eres un novelista galardonado. Tu tarea es escribir una historia completa en español, de alta calidad literaria, siguiendo EXACTAMENTE el blueprint narrativo proporcionado.

## PREMISA DE LA HISTORIA
- **Moraleja:** ${data.moraleja}
- **Conflicto Central:** ${data.conflicto}
- **Escenario:** ${data.escenario}
- **Tono:** ${data.tono_sugerido}

## BLUEPRINT NARRATIVO (12 Pasos del Viaje del Héroe)
${pasosTexto}

## INSTRUCCIONES DE ESCRITURA:
1. Escribe la historia completa como PROSA CONTINUA (no como lista de pasos).
2. Cada paso del blueprint corresponde a un capítulo o sección.
3. Usa descripciones vívidas, diálogos naturales y transiciones fluidas.
4. La moraleja debe ser implícita, nunca declarada explícitamente.
5. Extensión objetivo: 3000-5000 palabras.
6. NO incluyas metadatos, títulos de pasos de Campbell ni comentarios.
7. Comienza directamente con la narración.

/no_think

---

`;

// Escapar comillas y caracteres problemáticos para la línea de comandos
const escapedPrompt = megaPrompt
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"')
  .replace(/\$/g, '\\$')
  .replace(/`/g, '\\`');

const outputFile = `/tmp/historia_${data.ID}_raw.txt`;

const command = `llama-cli -m ~/.cache/llama.cpp/unsloth_Qwen3.5-27B-GGUF_Qwen3.5-27B-UD-Q4_K_XL.gguf -ngl 999 -c 8192 -n 8000 --temp 0.8 --repeat-penalty 1.1 -p "${escapedPrompt}" > ${outputFile} 2>/dev/null`;

return [{
  json: {
    ...data,
    llama_command: command,
    output_file: outputFile
  }
}];

// Leer el archivo de historia generado
const fs = require('fs');
const prevData = $('📝 Compilar Prompt del Escritor').first().json;
const outputFile = prevData.output_file;

let rawStory;
try {
  rawStory = fs.readFileSync(outputFile, 'utf-8');
} catch (e) {
  throw new Error(`No se pudo leer el archivo de historia: ${outputFile}. Error: ${e.message}`);
}

// Limpiar el prompt del inicio si llama-cli lo incluyó
const storyLines = rawStory.split('\n');
const startIndex = storyLines.findIndex(line => line.startsWith('---'));
const cleanStory = startIndex >= 0 
  ? storyLines.slice(startIndex + 1).join('\n').trim()
  : rawStory.trim();

if (cleanStory.length < 500) {
  throw new Error(`Historia demasiado corta (${cleanStory.length} caracteres). Posible error de generación.`);
}

return [{
  json: {
    ...prevData,
    historia_raw: cleanStory,
    longitud_caracteres: cleanStory.length,
    longitud_palabras: cleanStory.split(/\s+/).length
  }
}];

// Preparar el texto final editado
const ollamaResponse = $input.first().json.response;
const prevData = $('📄 Leer Historia Raw').first().json;

// Si el editor devolvió contenido válido, usarlo; sino, usar el raw
const historiaFinal = (ollamaResponse && ollamaResponse.trim().length > 500)
  ? ollamaResponse.trim()
  : prevData.historia_raw;

// Componer el archivo Markdown final con metadatos
const fechaHoy = new Date().toISOString().split('T')[0];
const markdown = `---\ntitle: "Historia ${prevData.ID}"\nfecha_generacion: ${fechaHoy}\ntema: "${prevData.Tema}"\nmoraleja: "${prevData.moraleja}"\nescenario: "${prevData.escenario}"\npalabras: ${historiaFinal.split(/\s+/).length}\nagente_escritor: Qwen3.5-27B-UD-Q4\nagente_editor: nemotron-3-nano\n---\n\n${historiaFinal}\n`;

const finalPath = `/var/opt/innovalabs/historias/Historia_${prevData.ID}.md`;

return [{
  json: {
    ...prevData,
    historia_final: markdown,
    final_path: finalPath,
    palabras_final: historiaFinal.split(/\s+/).length
  }
}];

// Guardar historia en el filesystem
const fs = require('fs');
const path = require('path');
const data = $input.first().json;

const dirPath = '/var/opt/innovalabs/historias';
const filePath = data.final_path;

// Crear directorio si no existe
try {
  fs.mkdirSync(dirPath, { recursive: true });
} catch(e) {
  // Directorio ya existe, OK
}

// Escribir el archivo
try {
  fs.writeFileSync(filePath, data.historia_final, 'utf-8');
} catch(e) {
  throw new Error(`No se pudo guardar la historia en ${filePath}: ${e.message}`);
}

const stats = fs.statSync(filePath);

return [{
  json: {
    ...data,
    saved: true,
    file_size_bytes: stats.size,
    saved_at: new Date().toISOString()
  }
}];

// Limpieza post-ejecución
const prevData = $input.first().json;

// Log de resumen
const summary = {
  id: prevData.ID,
  tema: prevData.Tema,
  moraleja: prevData.moraleja,
  palabras: prevData.palabras_final,
  archivo: prevData.final_path,
  timestamp: new Date().toISOString()
};

console.log('✅ Historia generada:', JSON.stringify(summary, null, 2));

return [{ json: summary }];

// Extraer información del error
const errorData = $input.first().json;

// Intentar recuperar el ID del item que estaba siendo procesado
let itemId = 'UNKNOWN';
let errorMsg = 'Error desconocido';

try {
  // n8n pasa la info del error en la ejecución
  if (errorData.execution) {
    errorMsg = errorData.execution.error?.message || JSON.stringify(errorData.execution.error || {});
  }
  // Intentar obtener el ID del contexto
  const allData = errorData.workflow?.nodes || [];
  // Buscar en los datos del nodo que falló
  itemId = errorData.execution?.lastNodeExecuted || 'UNKNOWN';
} catch(e) {
  errorMsg = `Error en recovery: ${e.message}`;
}

// Detectar si fue OOM
const isOOM = errorMsg.toLowerCase().includes('out of memory') || 
              errorMsg.toLowerCase().includes('oom') ||
              errorMsg.toLowerCase().includes('killed');

return [{
  json: {
    itemId: itemId,
    errorMessage: errorMsg.substring(0, 500),
    isOOM: isOOM,
    timestamp: new Date().toISOString(),
    estadoFinal: isOOM ? 'FAILED_OOM' : 'FAILED'
  }
}];

console.log('⚠️ Error no-OOM registrado:', $json.errorMessage);
console.log('Timestamp:', $json.timestamp);
return [$input.first()];
